import argparse
from kafka import KafkaAdminClient, KafkaProducer, KafkaConsumer
import time

parser = argparse.ArgumentParser(description='Kafka Topic Manager')
parser.add_argument('--bootstrap-servers', type=str, nargs='+', required=True, help='list of bootstrap servers')
parser.add_argument('--topic', type=str, required=True, help='the topic to be managed')
parser.add_argument('--num-partitions', type=int, default=1, help='number of partitions for the topic')
parser.add_argument('--replication-factor', type=int, default=1, help='replication factor for the topic')

args = parser.parse_args()

def create_topic(admin_client, topic, num_partitions, replication_factor):
    config = {'value.serializer': 'bytes', 'key.serializer': 'bytes'}
    if admin_client:
        admin_client.create_topics(
            topics={topic: {
                'num_partitions': num_partitions,
                'replication_factor': replication_factor,
                'config': config
            }}
        )
    time.sleep(2)  # Wait for the topic to be created

def delete_topic(admin_client, topic):
    if admin_client:
        admin_client.delete_topics([topic])
        time.sleep(2)  # Wait for the topic deletion

if __name__ == "__main__":
    bootstrap_servers = args.bootstrap_servers
    topic = args.topic
    num_partitions = args.num_partitions
    replication_factor = args.replication_factor

    admin_client = KafkaAdminClient(bootstrap_servers=bootstrap_servers)
    create_topic(admin_client, topic, num_partitions, replication_factor)

    time.sleep(5)  # Wait a bit for the script to run
    delete_topic(admin_client, topic)